SELECT art.id, art.title, art.summary, art.author_id as authorId, u.nickname as authorName, art.is_published as isPublished, art.created_at as createdAt, art.category_id as categoryId FROM article art JOIN category c ON art.category_id = c.id JOIN user u ON art.author_id = u.id WHERE art.is_deleted = 0
AND art.is_published = #{isPublished}
AND art.author_id = #{userId}
AND ( c.id = #{categoryId} OR c.level1_id = #{categoryId} OR c.level2_id = #{categoryId} )
AND EXISTS ( SELECT 1 FROM article_tag at WHERE at.article_id = art.id AND at.tag_id IN #{tagId} )
ORDER BY art.created_at DESC LIMIT #{offset}, #{size}

SELECT
art.id,
art.title,
art.summary,
art.author_id as authorId,
u.nickname as authorName,
art.is_published as isPublished,
art.created_at as createdAt,
art.category_id as categoryId
FROM article art
JOIN category c ON art.category_id = c.id
JOIN user u ON art.author_id = u.id
WHERE
art.is_deleted = 0

    AND art.is_published = #{isPublished}


    AND art.author_id = #{userId}


    AND (
    c.id = #{categoryId}
    OR c.level1_id = #{categoryId}
    OR c.level2_id = #{categoryId}
    )


    AND art.id IN (
    SELECT at.article_id as id
    FROM article_tag at
    WHERE at.tag_id IN
    #{tagId}
    GROUP BY at.article_id
    HAVING COUNT(DISTINCT at.tag_id) = #{tagSize}
    )

ORDER BY art.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(DISTINCT art.id)
FROM article art
JOIN category c ON art.category_id = c.id
WHERE art.is_deleted = 0

    AND art.is_published = #{isPublished}


    AND art.author_id = #{userId}


    AND (c.id = #{categoryId} OR c.level1_id = #{categoryId} OR c.level2_id = #{categoryId})


    AND EXISTS (
    SELECT 1 FROM article_tag at
    WHERE at.article_id = art.id AND at.tag_id IN
    #{tagId}
    )

SELECT COUNT(DISTINCT art.id)
FROM article art
JOIN category c ON art.category_id = c.id
WHERE art.is_deleted = 0

    AND art.is_published = #{isPublished}


    AND art.author_id = #{userId}


    AND (c.id = #{categoryId} OR c.level1_id = #{categoryId} OR c.level2_id = #{categoryId})


    AND art.id IN (
    SELECT at.article_id FROM article_tag at
    WHERE at.tag_id IN
    #{tagId}
    GROUP BY at.article_id
    HAVING COUNT(DISTINCT at.tag_id) = #{tagSize}
    )
